#' An internal customized ggplot2 theme for all the plots
#' generated by ViSAGE
#'
#' @noRd
boris_theme <- function(){
  ggplot2::theme_bw() +
    ggplot2::theme(
      axis.text       = ggplot2::element_text(color = "black", size = 16),
      axis.title      = ggplot2::element_text(colour = "black", face = "bold", size = 16),
      legend.text     = ggplot2::element_text(colour = "black", size = 16),
      legend.position = "none",
      legend.title    = ggplot2::element_blank(),
      panel.grid      = ggplot2::element_blank(),
      panel.background = ggplot2::element_rect(fill = "white", colour = NA),
      panel.border    = ggplot2::element_rect(colour = "black"),
      text            = ggplot2::element_text(colour = "black", size = 16)
    )
}

#####################################################################################################################
## The function below runs the multi-generation future simulation of a population
### It makes selection and crosses for 20 generations and returns 
#' Simulation of 20-generation selection for an initial breeding population 
#'
#' @param pop base population, generation zero
#' @param intensity selection intensity in percentage
#' @param direction selection direction, directional high or low values
#' @param trait target trait for selection; choose one of the three traits 
#' @param crop selected crop among maize, avocado, and strawberry
#' @param SP.crop the simulation paramaters container, an alphaSimR's object
#'
#' @returns a list of three elements: pop.list, a data frame of genetic values, and data frame of phenotypes.
#' @noRd
#'
multi.gener.sim <- function(pop = pop, intensity = 20, direction = "Higher values", 
                            trait, crop = "Maize", SP.crop){
  ####### Embed a simulation --------------- ##
  set.seed(900)
  pop.size = pop@nInd
  col.names <- colnames(pop@gv)
  trait.num = which(col.names == trait)
  direct = ifelse(direction == "Higher values", TRUE, FALSE)
  # h2.list <- list(Maize = c(0.9, 0.7, 0.8), 
  #                 Avocado = c(0.8, 0.8, 0.9), 
  #                 Strawberry = c(0.8, 0.8, 0.7))
  h2.list <- switch(crop,
                    "Maize" = c(0.9, 0.7, 0.8),
                    "Avocado" = c(0.8, 0.8, 0.9),
                    "Strawberry" = c(0.8, 0.8, 0.9),
                    NULL)
  # SP.crop <- switch(crop,
  #                   "Maize" = SP(),
  #                   "Avocado" = SP.avocado(),
  #                   "Strawberry" = SP.strawberry(),
  #                   SP)
  # pop.dt <- data.frame(col.names[1] = NA, col.names[2] = NA, col.names[3] = NA)
  pop.list <- list()
  pop <- AlphaSimR::randCross(pop, nCrosses = 100, nProgeny = 10, simParam = SP.crop)
  pop <- AlphaSimR::setPheno(pop, h2 = h2.list, simParam = SP.crop)
  pop.gv.dt <- data.frame(Generation = rep(0, nrow(pop@gv)), as.data.frame(pop@gv))
  pop.pv.dt <- data.frame(Generation = rep(0, nrow(pop@pheno)), as.data.frame(pop@pheno))
  for(generation in 1:20){
    pop = AlphaSimR::selectCross(pop=pop, use="pheno", nInd = intensity*pop.size/100,
                      nCrosses=100, nProgeny = 10, trait = trait.num, selectTop = direct, 
                      simParam = SP.crop)
    pop = AlphaSimR::setPheno(pop, h2 = h2.list, simParam = SP.crop)
    
    pop.gv.dt.temp <- data.frame(Generation = rep(generation, nrow(pop@gv)),
                              as.data.frame(pop@gv))
    pop.pv.dt.temp <- data.frame(Generation = rep(generation, nrow(pop@pheno)),
                              as.data.frame(pop@pheno))
    pop.gv.dt <- rbind(pop.gv.dt, pop.gv.dt.temp)
    pop.pv.dt <- rbind(pop.pv.dt, pop.pv.dt.temp)
    pop.list[[generation]] <- pop
  }
  combined.dt <- rbind(dplyr::mutate(pop.gv.dt, Type = "Genetic"), 
                       dplyr::mutate(pop.pv.dt, Type = "Phenotypic"))
  out.list <- list(popList = pop.list, gv = pop.gv.dt, pheno = pop.pv.dt, comb = combined.dt)
  return(out.list)
} # End of function multi.gener.sim
