#####################################################################################################################
#' Summarize simulation results
#' 
#' @description
#' Summarize the simulation results by the computing the quantile chosen by the user.#' 
#'
#' @param data The data frame of the simulation results
#' @param quartile Define the quartile from c(25,50,75,100)
#' @param pivot A boolean to determine whether to pivot longer or not
#'
#' @returns A data frame with summarized values
#' @noRd
#'
summary.simulation <- function(data, quartile = 50, pivot = F){
  summary.dt <- dplyr::group_by(data, Generation) |> 
    dplyr::summarise_at(names(data[,-1]), ~ stats::quantile(., probs = quartile/100)) |> 
    dplyr::mutate_at(names(data[,-1]), ~ ifelse(. > 0, ., 2)) |> 
    as.data.frame()
  # pivot_longer(., 2:ncol(data), names_to = "variate", values_to = "values") %>%
  # mutate(., values = ifelse(values > 0, values, 2))
  if(pivot == T){
    summary.dt <- summary.dt |> 
    tidyr::pivot_longer(2:ncol(data), names_to = "variate", values_to = "values") |> 
    as.data.frame()
    # mutate(., values = ifelse(values > 0, values, 2))
  }
  return(summary.dt)
} # End of function summary.simulation
