#####################################################################################################################
### The first argument is the output from the summary.simulation function

#' Draw a genetic gain plot
#'
#' @description
#' A function to draw dot plot to depict the temporal trend of the population 
#' quantile over 20 generations. This function is used in the Fun panel only.
#' 
#' @param dt a data frame of simulated phenotypes across 20 generations. 
#' It is an output from the summary.simulation function.
#' @param trait the desired trait to be plotted.
#' @param col the color of the line and dots plotted
#' @param annotate.bottom A string to be written at the bottom left
#' @param annotate.top A string to be written at the top left
#' @param draw.arrow a boolean to determine whether to draw a horizontal arrow. Default = FALSE.
#'
#' @returns a line graph with dots showing the phenotypes across 20 generations. It is a ggplot2 object.
#' @noRd
#'
draw.genetic.gain.plot <- function(dt, trait, col = "black", annotate.bottom,
                                   annotate.top, draw.arrow = F){
  tmp_dt <- dplyr::filter(dt, variate == trait)
  trait2 <- switch(trait,
                   "StemDiameter" = "Stem diameter (mm)",
                   "TasselLength" = "Tassel length (cm)",
                   "FruitLength" = "Fruit length (cm)",
                   "FruitWidth"  = "Fruit width (cm)",
                   "PlantHeight" = "Plant height (cm)",
                   paste0(trait, " (cm)"))
  
  label.size <- 5
  y.max <- 1.5*max(tmp_dt$values)
  y.min <- 0.5*min(tmp_dt$values)
  p <- ggplot2::ggplot(data = tmp_dt, ggplot2::aes(x = Generation, y = values)) +
    ggplot2::geom_line(linewidth = 1) + ggplot2::geom_point(size = 4, color = col) +
    boris_theme() + ggplot2::labs(y = trait2, x = "Generation") +
    ggplot2::annotate(geom = "text", x = 2, y = 1, label = annotate.bottom, 
                      size =label.size, color = col, fontface = "bold") +
    ggplot2::annotate(geom = "text", x = 2, y = y.max-2, label = annotate.top, 
                      size =label.size, color = col, fontface = "bold")
  
  if(draw.arrow == TRUE){
    p <- p + ggplot2::coord_cartesian(ylim = c(-10, y.max), xlim = c(0,20)) +
      ggplot2::annotate("segment", x = 3, y = -8, xend = 17, yend = -8, linewidth = 2, 
                        color = "black", arrow = ggplot2::arrow()) +
      ggplot2::annotate(geom="text", x= 10, y = -5, label = "Time", size = label.size, 
                        color = "black", fontface = "bold")
  }else{
    p <- p + ggplot2::coord_cartesian(ylim = c(0, y.max), xlim = c(0,20))
  }
  return(p)
} # End of function draw.genetic.gain.plot
